import { getDb, nextNumber, type Db } from '../db'
import type {
  Purchase,
  PaymentStatus,
  Uom,
  MaterialType,
  PurchaseMode,
  MachineBasis,
  PurchaseTransportBasis,
  PurchaseTransporter,
  PurchaseMachine
} from '@shared/types'
import { derivePaymentStatus, toCm, properCase } from '@shared/types'
import { addMovement, rawLocationBalance, finishedBalance } from './movements'
import { ensureDefaultLocation } from './stockLocations'
import { plantUomFactors } from './plants'

function round2(n: number): number {
  return Math.round((Number(n) + Number.EPSILON) * 100) / 100
}

/** A transporter line as accepted from the UI. */
interface TransporterInput {
  transporter_id: number
  vehicle_no?: string
  basis?: PurchaseTransportBasis
  qty?: number
  rate?: number
  /** Used when basis is 'flat' (or omitted). */
  charge?: number
}

/** Replace the transporter + machine lines for a purchase. */
async function writeChildLines(
  d: Db,
  purchaseId: number,
  transporters?: TransporterInput[],
  machines?: { asset_id: number; basis?: MachineBasis; qty?: number; rate?: number; outsource_id?: number | null }[]
): Promise<void> {
  await d.prepare(`DELETE FROM purchase_transporters WHERE purchase_id = ?`).run(purchaseId)
  await d.prepare(`DELETE FROM purchase_machines WHERE purchase_id = ?`).run(purchaseId)
  const tStmt = d.prepare(
    `INSERT INTO purchase_transporters (purchase_id, transporter_id, vehicle_no, basis, qty, rate, charge) VALUES (?, ?, ?, ?, ?, ?, ?)`
  )
  for (const t of transporters ?? []) {
    if (!t.transporter_id) continue
    // 'trip'/'uom' compute charge = qty × rate; 'flat' uses the entered charge directly.
    const basis: PurchaseTransportBasis = t.basis === 'trip' || t.basis === 'uom' ? t.basis : 'flat'
    const qty = basis === 'flat' ? 0 : Number(t.qty) || 0
    const rate = basis === 'flat' ? 0 : Number(t.rate) || 0
    const charge = basis === 'flat' ? round2(Number(t.charge) || 0) : round2(qty * rate)
    await tStmt.run(purchaseId, t.transporter_id, properCase(t.vehicle_no || ''), basis, qty, rate, charge)
  }
  const mStmt = d.prepare(
    `INSERT INTO purchase_machines (purchase_id, asset_id, basis, qty, rate, amount, outsource_id) VALUES (?, ?, ?, ?, ?, ?, ?)`
  )
  for (const m of machines ?? []) {
    if (!m.asset_id) continue
    const basis: MachineBasis = m.basis === 'cm' ? 'cm' : 'hour'
    const qty = Number(m.qty) || 0
    const rate = Number(m.rate) || 0
    await mStmt.run(purchaseId, m.asset_id, basis, qty, rate, round2(qty * rate), m.outsource_id ?? null)
  }
}

/** Full purchase with its transporter + machine lines (for the edit modal). */
export async function getPurchaseDetail(payload: { id: number }): Promise<Purchase | null> {
  const d = getDb()
  const pu = (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(payload.id)) as Purchase | undefined
  if (!pu) return null
  pu.transporters = (await d
    .prepare(
      `SELECT pt.*, t.name AS transporter_name FROM purchase_transporters pt
       JOIN transporters t ON t.id = pt.transporter_id WHERE pt.purchase_id = ? ORDER BY pt.id`
    )
    .all(payload.id)) as PurchaseTransporter[]
  pu.machines = (await d
    .prepare(
      `SELECT pm.*, a.name AS asset_name, o.name AS outsource_name FROM purchase_machines pm
       JOIN assets a ON a.id = pm.asset_id
       LEFT JOIN outsource o ON o.id = pm.outsource_id WHERE pm.purchase_id = ? ORDER BY pm.id`
    )
    .all(payload.id)) as PurchaseMachine[]
  return pu
}

export interface PurchaseFilter {
  supplier_id?: number
  plant_id?: number
  payment_status?: PaymentStatus
  from?: string
  to?: string
}

export async function listPurchases(filter: PurchaseFilter = {}): Promise<Purchase[]> {
  const d = getDb()
  const where: string[] = []
  const params: Record<string, unknown> = {}
  if (filter.supplier_id) {
    where.push('pu.supplier_id = @supplier_id')
    params.supplier_id = filter.supplier_id
  }
  if (filter.plant_id) {
    where.push('pu.plant_id = @plant_id')
    params.plant_id = filter.plant_id
  }
  if (filter.payment_status) {
    where.push('pu.payment_status = @payment_status')
    params.payment_status = filter.payment_status
  }
  if (filter.from) {
    where.push('pu.date >= @from')
    params.from = filter.from
  }
  if (filter.to) {
    where.push('pu.date <= @to')
    params.to = filter.to
  }
  const clause = where.length ? `WHERE ${where.join(' AND ')}` : ''
  return (await d
    .prepare(
      `SELECT pu.*, s.name AS supplier_name, p.name AS plant_name, l.name AS stock_location_name,
        o.name AS outsource_name, o.head AS outsource_head, fp.name AS from_plant_name,
        (SELECT COALESCE(SUM(charge),0) FROM purchase_transporters pt WHERE pt.purchase_id = pu.id) AS transport_total,
        (SELECT COALESCE(SUM(amount),0) FROM purchase_machines pm WHERE pm.purchase_id = pu.id) AS machine_total
       FROM purchases pu
       JOIN suppliers s ON s.id = pu.supplier_id
       JOIN plants p ON p.id = pu.plant_id
       JOIN stock_locations l ON l.id = pu.stock_location_id
       LEFT JOIN outsource o ON o.id = pu.outsource_id
       LEFT JOIN plants fp ON fp.id = pu.from_plant_id
       ${clause}
       ORDER BY pu.date DESC, pu.id DESC`
    )
    .all(params)) as Purchase[]
}

function computeAmount(rate: number | null, qty: number): number | null {
  if (rate == null || isNaN(rate)) return null
  return Math.round((rate * qty + Number.EPSILON) * 100) / 100
}

function roundQty(n: number): number {
  return Math.round((n + Number.EPSILON) * 1000) / 1000
}

export interface PurchaseInput {
  id?: number
  supplier_id: number
  plant_id: number
  stock_location_id?: number
  /** 'raw' (default) buys raw material into a location; 'finished' buys a product into finished stock. */
  material_type?: MaterialType
  /** Product name, required when material_type = 'finished'. */
  product_name?: string
  /** Optional outsource vendor this purchase came through. */
  outsource_id?: number | null
  /** 'purchase' (default) buys from supplier; 'mining' extracts from supplier's land (royalty rate). */
  purchase_mode?: PurchaseMode
  /** Inter-plant: source plant this stock came from (set when mirroring a direct sale). */
  from_plant_id?: number | null
  /** The direct sale that created this purchase (inter-plant mirror). */
  linked_dispatch_id?: number | null
  /** Transporter lines (transport for bringing the material in). */
  transporters?: TransporterInput[]
  /** Machine-usage lines (cost posts as a plant equipment-rent cost; optional vendor payable). */
  machines?: { asset_id: number; basis?: MachineBasis; qty?: number; rate?: number; outsource_id?: number | null }[]
  uom: Uom
  quantity: number
  rate: number | null
  paid_amount: number
  payment_status: PaymentStatus
  /** Challan / delivery-note no; blank → auto-generated. */
  challan_no?: string
  date: string
  remarks: string
}

export async function createPurchase(p: PurchaseInput): Promise<Purchase> {
  const d = getDb()
  if (!(p.quantity > 0)) throw new Error('Quantity must be greater than 0.')
  const mode: PurchaseMode = p.purchase_mode === 'mining' ? 'mining' : 'purchase'
  // Mining always yields raw material; only a straight purchase can be finished goods.
  const kind: MaterialType = mode === 'purchase' && p.material_type === 'finished' ? 'finished' : 'raw'
  const product = kind === 'finished' ? properCase(p.product_name || '') : ''
  if (kind === 'finished' && !product) throw new Error('Select a product to purchase.')
  // A stock-location is always stored (NOT NULL); for finished purchases it is the
  // plant's default and is not used for finished-goods tracking.
  const locId = p.stock_location_id || (await ensureDefaultLocation(p.plant_id))
  const uom: Uom = (['CM', 'TON', 'CFT'] as const).includes(p.uom) ? p.uom : 'CM'
  const qtyCm = roundQty(toCm(p.quantity, uom, await plantUomFactors(p.plant_id)))
  const amount = computeAmount(p.rate, p.quantity)
  const id = await d.transaction(async () => {
    const no = await nextNumber('PUR', 'purchase')
    const challan = (p.challan_no ?? '').trim() || (await nextNumber('CHN', 'challan'))
    const info = await d
      .prepare(
        `INSERT INTO purchases
          (purchase_no, supplier_id, plant_id, stock_location_id, material_type, purchase_mode, product_name, outsource_id, from_plant_id, linked_dispatch_id, uom, quantity, qty_cm, rate, amount, paid_amount, payment_status, challan_no, date, remarks)
         VALUES (@purchase_no,@supplier_id,@plant_id,@stock_location_id,@material_type,@purchase_mode,@product_name,@outsource_id,@from_plant_id,@linked_dispatch_id,@uom,@quantity,@qty_cm,@rate,@amount,@paid_amount,@payment_status,@challan_no,@date,@remarks)`
      )
      .run({
        purchase_no: no,
        challan_no: challan,
        supplier_id: p.supplier_id,
        plant_id: p.plant_id,
        stock_location_id: locId,
        material_type: kind,
        purchase_mode: mode,
        product_name: product,
        outsource_id: p.outsource_id ?? null,
        from_plant_id: p.from_plant_id ?? null,
        linked_dispatch_id: p.linked_dispatch_id ?? null,
        uom,
        quantity: p.quantity,
        qty_cm: qtyCm,
        rate: p.rate,
        amount,
        paid_amount: p.paid_amount || 0,
        payment_status: derivePaymentStatus(amount ?? 0, p.paid_amount || 0),
        date: p.date,
        remarks: p.remarks ?? ''
      })
    await writeChildLines(d, Number(info.lastInsertRowid), p.transporters, p.machines)
    if (kind === 'finished') {
      await addMovement(d, {
        type: 'purchase',
        material_type: 'finished',
        ref_no: no,
        plant_id: p.plant_id,
        product_name: product,
        change_qty: qtyCm,
        date: p.date,
        note: 'Finished goods purchased'
      })
    } else {
      await addMovement(d, {
        type: 'purchase',
        material_type: 'raw',
        ref_no: no,
        plant_id: p.plant_id,
        stock_location_id: locId,
        change_qty: qtyCm,
        date: p.date,
        note: 'Raw material received'
      })
    }
    return Number(info.lastInsertRowid)
  })
  return (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(id)) as Purchase
}

export async function updatePurchase(p: PurchaseInput): Promise<Purchase> {
  const d = getDb()
  if (!p.id) throw new Error('Missing purchase id.')
  if (!(p.quantity > 0)) throw new Error('Quantity must be greater than 0.')
  const old = (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(p.id)) as Purchase
  if (!old) throw new Error('Purchase not found.')
  if (old.linked_dispatch_id)
    throw new Error('This purchase was created by an inter-plant sale — edit that sale instead.')
  const mode: PurchaseMode = p.purchase_mode === 'mining' ? 'mining' : 'purchase'
  const kind: MaterialType = mode === 'purchase' && p.material_type === 'finished' ? 'finished' : 'raw'
  const product = kind === 'finished' ? properCase(p.product_name || '') : ''
  if (kind === 'finished' && !product) throw new Error('Select a product to purchase.')
  const locId = p.stock_location_id || old.stock_location_id || (await ensureDefaultLocation(p.plant_id))
  const uom: Uom = (['CM', 'TON', 'CFT'] as const).includes(p.uom) ? p.uom : 'CM'
  const qtyCm = roundQty(toCm(p.quantity, uom, await plantUomFactors(p.plant_id)))
  const amount = computeAmount(p.rate, p.quantity)
  await d.transaction(async () => {
    const challan = (p.challan_no ?? '').trim() || old.challan_no || (await nextNumber('CHN', 'challan'))
    await d.prepare(
      `UPDATE purchases SET supplier_id=@supplier_id, plant_id=@plant_id, stock_location_id=@stock_location_id,
         material_type=@material_type, purchase_mode=@purchase_mode, product_name=@product_name, outsource_id=@outsource_id,
         uom=@uom, quantity=@quantity, qty_cm=@qty_cm, rate=@rate, amount=@amount, paid_amount=@paid_amount,
         payment_status=@payment_status, challan_no=@challan_no, date=@date, remarks=@remarks WHERE id=@id`
    ).run({
      id: p.id,
      challan_no: challan,
      supplier_id: p.supplier_id,
      plant_id: p.plant_id,
      stock_location_id: locId,
      material_type: kind,
      purchase_mode: mode,
      product_name: product,
      outsource_id: p.outsource_id ?? null,
      uom,
      quantity: p.quantity,
      qty_cm: qtyCm,
      rate: p.rate,
      amount,
      paid_amount: p.paid_amount || 0,
      payment_status: derivePaymentStatus(amount ?? 0, p.paid_amount || 0),
      date: p.date,
      remarks: p.remarks ?? ''
    })
    await writeChildLines(d, p.id!, p.transporters, p.machines)
    // Rebuild the linked stock movement (kind may have changed on edit).
    await d.prepare(`DELETE FROM stock_movements WHERE ref_no=? AND type='purchase'`).run(old.purchase_no)
    if (kind === 'finished') {
      await addMovement(d, {
        type: 'purchase',
        material_type: 'finished',
        ref_no: old.purchase_no,
        plant_id: p.plant_id,
        product_name: product,
        change_qty: qtyCm,
        date: p.date,
        note: 'Finished goods purchased'
      })
    } else {
      await addMovement(d, {
        type: 'purchase',
        material_type: 'raw',
        ref_no: old.purchase_no,
        plant_id: p.plant_id,
        stock_location_id: locId,
        change_qty: qtyCm,
        date: p.date,
        note: 'Raw material received'
      })
    }

    // Guard against negative balances at any affected location/product (old & new).
    if ((await rawLocationBalance(d, old.stock_location_id)) < 0)
      throw new Error('Edit would make the original location stock negative.')
    if (kind === 'raw' && (await rawLocationBalance(d, locId)) < 0)
      throw new Error('Edit would make the location stock negative.')
    if (old.material_type === 'finished' && old.product_name &&
        (await finishedBalance(d, old.plant_id, old.product_name)) < 0)
      throw new Error('Edit would make the original finished-goods stock negative.')
    if (kind === 'finished' && (await finishedBalance(d, p.plant_id, product)) < 0)
      throw new Error('Edit would make the finished-goods stock negative.')
  })
  return (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(p.id)) as Purchase
}

export async function deletePurchase(payload: { id: number }): Promise<{ ok: boolean; error?: string }> {
  const d = getDb()
  const old = (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(payload.id)) as Purchase
  if (!old) return { ok: false, error: 'Purchase not found.' }
  if (old.linked_dispatch_id)
    return { ok: false, error: 'This purchase was created by an inter-plant sale — delete that sale instead.' }
  try {
    await d.transaction(async () => {
      await d.prepare(`DELETE FROM stock_movements WHERE ref_no=? AND type='purchase'`).run(
        old.purchase_no
      )
      if (old.material_type === 'finished') {
        if (old.product_name && (await finishedBalance(d, old.plant_id, old.product_name)) < 0)
          throw new Error('Cannot delete: these finished goods have already been dispatched or sold.')
      } else if ((await rawLocationBalance(d, old.stock_location_id)) < 0) {
        throw new Error('Cannot delete: this material has already been consumed in production.')
      }
      await d.prepare(`DELETE FROM purchase_transporters WHERE purchase_id = ?`).run(payload.id)
      await d.prepare(`DELETE FROM purchase_machines WHERE purchase_id = ?`).run(payload.id)
      await d.prepare(`DELETE FROM purchases WHERE id = ?`).run(payload.id)
    })
    return { ok: true }
  } catch (e) {
    return { ok: false, error: (e as Error).message }
  }
}

/**
 * Remove a purchase that mirrors an inter-plant sale (reverses its finished stock).
 * Used by the dispatch service; runs inside the caller's transaction. Skips the
 * linked-dispatch guard (the dispatch owns this row), but still protects stock.
 */
export async function removeLinkedPurchase(id: number): Promise<void> {
  const d = getDb()
  const old = (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(id)) as Purchase | undefined
  if (!old) return
  await d.prepare(`DELETE FROM stock_movements WHERE ref_no=? AND type='purchase'`).run(old.purchase_no)
  if (
    old.material_type === 'finished' &&
    old.product_name &&
    (await finishedBalance(d, old.plant_id, old.product_name)) < 0
  )
    throw new Error('Cannot reverse: the received goods have already been sold/dispatched at the destination plant.')
  await d.prepare(`DELETE FROM purchase_transporters WHERE purchase_id = ?`).run(id)
  await d.prepare(`DELETE FROM purchase_machines WHERE purchase_id = ?`).run(id)
  await d.prepare(`DELETE FROM purchases WHERE id = ?`).run(id)
}

export async function setPurchasePayment(payload: {
  id: number
  paid_amount: number
  payment_status: PaymentStatus
}): Promise<Purchase> {
  const d = getDb()
  await d.prepare(`UPDATE purchases SET paid_amount=?, payment_status=? WHERE id=?`).run(
    payload.paid_amount || 0,
    payload.payment_status,
    payload.id
  )
  return (await d.prepare(`SELECT * FROM purchases WHERE id = ?`).get(payload.id)) as Purchase
}
