import { getDb } from '../db'
import type { Transporter } from '@shared/types'
import { properCase } from '@shared/types'
import { ensureUniqueName } from './names'
import { plantIdSet, writePartyPlants, attachPartyPlants, plantScopeSql } from './partyPlants'

export async function listTransporters(payload: { plant_id?: number } = {}): Promise<Transporter[]> {
  const d = getDb()
  const clause = payload.plant_id ? `WHERE ${plantScopeSql('t', 'transporter')}` : ''
  const rows = (await d
    .prepare(
      `SELECT t.*, co.name AS company_name, pl.name AS plant_name
       FROM transporters t
       LEFT JOIN companies co ON co.id = t.company_id
       LEFT JOIN plants pl ON pl.id = t.plant_id
       ${clause}
       ORDER BY t.name`
    )
    .all(payload)) as Transporter[]
  await attachPartyPlants(d, 'transporter', rows)
  for (const t of rows) {
    const agg = (await d
      .prepare(
        `SELECT
           COALESCE(SUM(trips),0) AS trips,
           COALESCE(SUM(total_cm),0) AS cm,
           COALESCE(SUM(amount),0) AS amt,
           COALESCE(SUM(diesel_amount),0) AS diesel
         FROM (
           SELECT trips, total_cm, amount, diesel_amount FROM rack_loadings WHERE transporter_id = @id
           UNION ALL
           SELECT trips, total_cm, amount, diesel_amount FROM rack_unloadings WHERE transporter_id = @id
         ) AS u`
      )
      .get({ id: t.id })) as { trips: number; cm: number; amt: number; diesel: number }
    const pay = (await d
      .prepare(
        `SELECT
           COALESCE(SUM(CASE WHEN direction='out' THEN amount ELSE 0 END),0) AS paid,
           COALESCE(SUM(CASE WHEN direction='in' THEN amount ELSE 0 END),0) AS recvd
         FROM payments WHERE party_type='transporter' AND party_id = ?`
      )
      .get(t.id)) as { paid: number; recvd: number }
    t.total_trips = round(agg.trips)
    t.total_cm = round(agg.cm)
    t.total_amount = round(agg.amt)
    t.diesel_amount = round(agg.diesel)
    t.paid_amount = round(pay.paid)
    // Balance payable = transport bills - diesel given - payments made (+ any refunds received)
    t.balance_amount = round(agg.amt - agg.diesel - pay.paid + pay.recvd)
  }
  return rows
}

export async function createTransporter(p: {
  name: string
  contact: string
  address: string
  remarks: string
  company_id?: number | null
  plant_id?: number | null
  plant_ids?: number[]
}): Promise<Transporter> {
  const d = getDb()
  await ensureUniqueName('transporters', p.name, { label: 'A transporter' })
  const plants = plantIdSet(p)
  const id = await d.transaction(async () => {
    const info = await d
      .prepare(
        `INSERT INTO transporters (name, contact, address, remarks, company_id, plant_id) VALUES (?, ?, ?, ?, ?, ?)`
      )
      .run(
        properCase(p.name),
        p.contact ?? '',
        p.address ?? '',
        p.remarks ?? '',
        p.company_id ?? null,
        plants[0] ?? null
      )
    const tid = Number(info.lastInsertRowid)
    await writePartyPlants(d, 'transporter', tid, plants)
    return tid
  })
  const row = (await d.prepare(`SELECT * FROM transporters WHERE id = ?`).get(id)) as Transporter
  await attachPartyPlants(d, 'transporter', [row])
  return row
}

export async function updateTransporter(p: {
  id: number
  name: string
  contact: string
  address: string
  remarks: string
  company_id?: number | null
  plant_id?: number | null
  plant_ids?: number[]
}): Promise<Transporter> {
  const d = getDb()
  await ensureUniqueName('transporters', p.name, { id: p.id, label: 'A transporter' })
  const plants = plantIdSet(p)
  await d.transaction(async () => {
    await d.prepare(
      `UPDATE transporters SET name=?, contact=?, address=?, remarks=?, company_id=?, plant_id=? WHERE id=?`
    ).run(
      properCase(p.name),
      p.contact ?? '',
      p.address ?? '',
      p.remarks ?? '',
      p.company_id ?? null,
      plants[0] ?? null,
      p.id
    )
    await writePartyPlants(d, 'transporter', p.id, plants)
  })
  const row = (await d.prepare(`SELECT * FROM transporters WHERE id = ?`).get(p.id)) as Transporter
  await attachPartyPlants(d, 'transporter', [row])
  return row
}

export async function deleteTransporter(payload: { id: number }): Promise<{ ok: boolean; error?: string }> {
  const d = getDb()
  const used = (await d
    .prepare(
      `SELECT
        (SELECT COUNT(*) FROM rack_loadings WHERE transporter_id = @id) +
        (SELECT COUNT(*) FROM rack_unloadings WHERE transporter_id = @id) AS c`
    )
    .get({ id: payload.id })) as { c: number }
  if (used.c > 0) {
    return { ok: false, error: 'Cannot delete: this transporter has rack loading/unloading records.' }
  }
  const paid = (await d
    .prepare(`SELECT COUNT(*) AS c FROM payments WHERE party_type='transporter' AND party_id = ?`)
    .get(payload.id)) as { c: number }
  if (paid.c > 0) {
    return { ok: false, error: 'Cannot delete: this transporter has payment records.' }
  }
  await d.transaction(async () => {
    await d.prepare(`DELETE FROM transporter_plants WHERE transporter_id = ?`).run(payload.id)
    await d.prepare(`DELETE FROM transporters WHERE id = ?`).run(payload.id)
  })
  return { ok: true }
}

function round(n: number): number {
  return Math.round((n + Number.EPSILON) * 100) / 100
}
